-- ============================================================================
-- Quiz Seed: Mark — Part 2 (Chapters 9–16)
-- 3 difficulties × 8 chapters = 128 total questions
--   kids:   3 per chapter  = 24
--   teens:  5 per chapter  = 40
--   adults: 8 per chapter  = 64
-- ============================================================================

-- ═══════════════ CHAPTERS 9–12 ═══════════════

-- ═══ Mark Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 9, 'kids', 1, 'What happened to Jesus'' clothes on the mountain?', 'They became shining, exceeding white as snow', 'They turned brown', 'They disappeared', 'They became heavy', 'a', 'Mark 9:3 — "And his raiment became shining, exceeding white as snow; so as no fuller on earth can white them."'),
('Mark', 9, 'kids', 2, 'Who appeared with Jesus on the mountain?', 'Moses and Elijah', 'Abraham and David', 'Adam and Noah', 'Samuel and Isaiah', 'a', 'Mark 9:4 — "And there appeared unto them Elias with Moses: and they were talking with Jesus."'),
('Mark', 9, 'kids', 3, 'What did Jesus say about being the greatest?', 'If any man desire to be first, the same shall be last of all and servant of all', 'The strongest person is the greatest', 'The richest person is the greatest', 'The oldest person is the greatest', 'a', 'Mark 9:35 — "If any man desire to be first, the same shall be last of all, and servant of all."'),
-- Teens
('Mark', 9, 'teens', 1, 'What did the voice from the cloud say at the Transfiguration?', 'This is my beloved Son: hear him', 'Behold the Lamb of God', 'Worship the Lord thy God only', 'Fear not, I am with you', 'a', 'Mark 9:7 — "And there was a cloud that overshadowed them: and a voice came out of the cloud, saying, This is my beloved Son: hear him."'),
('Mark', 9, 'teens', 2, 'What did the father of the demon-possessed boy cry out to Jesus?', 'Lord, I believe; help thou mine unbelief', 'I have no faith at all', 'I only believe in miracles I can see', 'I trust the physicians more', 'a', 'Mark 9:24 — "And straightway the father of the child cried out, and said with tears, Lord, I believe; help thou mine unbelief."'),
('Mark', 9, 'teens', 3, 'What did Jesus say about the kind of spirit that possessed the boy?', 'This kind can come forth by nothing, but by prayer and fasting', 'Any disciple can easily cast this out', 'This kind cannot be removed', 'This kind only leaves at sunset', 'a', 'Mark 9:29 — "And he said unto them, This kind can come forth by nothing, but by prayer and fasting."'),
('Mark', 9, 'teens', 4, 'What did Jesus do when the disciples argued about who was the greatest?', 'He set a little child in the midst of them and said receiving a child in His name is receiving Him', 'He chose Peter as the greatest', 'He told them to stop talking', 'He ignored their argument', 'a', 'Mark 9:36-37 — "And he took a child, and set him in the midst of them: and when he had taken him in his arms, he said unto them, Whosoever shall receive one of such children in my name, receiveth me."'),
('Mark', 9, 'teens', 5, 'What vivid warning did Jesus give about causing a little one to stumble?', 'It is better for him that a millstone were hanged about his neck, and he were cast into the sea', 'He should pay a fine to the temple', 'He should fast for a week', 'He should move to another city', 'a', 'Mark 9:42 — "And whosoever shall offend one of these little ones that believe in me, it is better for him that a millstone were hanged about his neck, and he were cast into the sea."'),
-- Adults
('Mark', 9, 'adults', 1, 'Which three disciples witnessed the Transfiguration?', 'Peter, James, and John', 'Peter, Andrew, and Matthew', 'James, John, and Thomas', 'Peter, Philip, and Bartholomew', 'a', 'Mark 9:2 — "And after six days Jesus taketh with him Peter, and James, and John, and leadeth them up into an high mountain apart by themselves."'),
('Mark', 9, 'adults', 2, 'What did Peter suggest building on the mount of Transfiguration?', 'Three tabernacles — one for Jesus, one for Moses, and one for Elijah', 'A permanent temple', 'An altar of sacrifice', 'A stone monument', 'a', 'Mark 9:5 — "Master, it is good for us to be here: and let us make three tabernacles; one for thee, and one for Moses, and one for Elias."'),
('Mark', 9, 'adults', 3, 'What did Jesus charge the three disciples after the Transfiguration?', 'To tell no man what they had seen until the Son of man were risen from the dead', 'To immediately tell everyone', 'To write it down in a book', 'To tell only the other nine disciples', 'a', 'Mark 9:9 — "And as they came down from the mountain, he charged them that they should tell no man what things they had seen, till the Son of man were risen from the dead."'),
('Mark', 9, 'adults', 4, 'What did Jesus say about Elias (Elijah) having already come?', 'That Elias has indeed come, and they have done unto him whatsoever they listed — referring to John the Baptist', 'That Elijah was still expected in the future', 'That the prophecy about Elijah was symbolic only', 'That Elijah appeared at the Transfiguration as fulfillment', 'a', 'Mark 9:13 — "But I say unto you, That Elias is indeed come, and they have done unto him whatsoever they listed, as it is written of him."'),
('Mark', 9, 'adults', 5, 'What does Jesus'' statement "All things are possible to him that believeth" teach about faith?', 'That genuine faith connects a person to the limitless power of God, making the impossible possible through Him', 'That humans have unlimited natural power', 'That faith is merely positive thinking', 'That believing guarantees material prosperity', 'a', 'Mark 9:23 — "Jesus said unto him, If thou canst believe, all things are possible to him that believeth."'),
('Mark', 9, 'adults', 6, 'What repeated phrase does Jesus use about hell (Gehenna) in verses 43-48?', 'Where their worm dieth not, and the fire is not quenched', 'Where there is weeping and gnashing of teeth', 'Where the darkness is eternal', 'Where the soul sleeps forever', 'a', 'Mark 9:44,46,48 — "Where their worm dieth not, and the fire is not quenched." Jesus quotes Isaiah 66:24 three times for emphasis.'),
('Mark', 9, 'adults', 7, 'What does Jesus mean by "Have salt in yourselves, and have peace one with another" in verse 50?', 'Believers should maintain their distinctive, preserving influence (salt) and live in harmony with each other', 'Literal salt should be added to all meals', 'Salt is a symbol of wealth and prosperity', 'Only peacemakers can enter the kingdom', 'a', 'Mark 9:50 — "Salt is good: but if the salt have lost his saltness, wherewith will ye season it? Have salt in yourselves, and have peace one with another."'),
('Mark', 9, 'adults', 8, 'How does the Transfiguration confirm Jesus'' identity and mission?', 'It reveals His pre-incarnate divine glory, connects Him to the Law (Moses) and Prophets (Elijah), and the Father''s voice affirms His unique Sonship', 'It was merely a vision with no theological meaning', 'It shows Jesus was equal to Moses and Elijah', 'It proves the disciples had spiritual powers', 'a', 'Mark 9:2-7 — The Transfiguration unveils Christ''s glory (v. 3), connects Him to the OT witness (v. 4), and the Father commands "Hear him" (v. 7), superseding Moses and Elijah.');

-- ═══ Mark Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 10, 'kids', 1, 'What did Jesus say when the disciples tried to keep the children away?', 'Suffer the little children to come unto me, and forbid them not', 'Children should wait until they are older', 'Only adults can come to me', 'Tell the children to go home', 'a', 'Mark 10:14 — "Suffer the little children to come unto me, and forbid them not: for of such is the kingdom of God."'),
('Mark', 10, 'kids', 2, 'What did the rich young man have a lot of?', 'Great possessions (riches)', 'Friends', 'Brothers and sisters', 'Animals', 'a', 'Mark 10:22 — "And he was sad at that saying, and went away grieved: for he had great possessions."'),
('Mark', 10, 'kids', 3, 'Who did Jesus heal on the road near Jericho?', 'Blind Bartimaeus', 'Deaf Matthew', 'Lame Zacchaeus', 'Sick Lazarus', 'a', 'Mark 10:46,52 — "Blind Bartimaeus, the son of Timaeus, sat by the highway side begging... And Jesus said unto him, Go thy way; thy faith hath made thee whole."'),
-- Teens
('Mark', 10, 'teens', 1, 'What did Jesus say about divorce when the Pharisees tested Him?', 'What God hath joined together, let not man put asunder', 'Divorce is acceptable for any reason', 'Marriage is not important', 'Moses'' law is the final word', 'a', 'Mark 10:9 — "What therefore God hath joined together, let not man put asunder."'),
('Mark', 10, 'teens', 2, 'What did Jesus say is hard for rich people to do?', 'Enter into the kingdom of God', 'Find good friends', 'Be healthy', 'Travel safely', 'a', 'Mark 10:23 — "How hardly shall they that have riches enter into the kingdom of God!"'),
('Mark', 10, 'teens', 3, 'What famous comparison did Jesus make about a rich man entering the kingdom?', 'It is easier for a camel to go through the eye of a needle than for a rich man to enter the kingdom of God', 'It is easier for a horse to fly', 'It is easier for a mountain to move', 'It is easier for the sun to stop', 'a', 'Mark 10:25 — "It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God."'),
('Mark', 10, 'teens', 4, 'What did James and John ask Jesus for?', 'To sit on His right and left hand in His glory', 'To be released from following Him', 'To go back to fishing', 'To lead the other ten disciples', 'a', 'Mark 10:37 — "They said unto him, Grant unto us that we may sit, one on thy right hand, and the other on thy left hand, in thy glory."'),
('Mark', 10, 'teens', 5, 'What did blind Bartimaeus cry out to Jesus?', 'Jesus, thou Son of David, have mercy on me', 'Jesus, give me money', 'Jesus, take me as your disciple', 'Jesus, destroy my enemies', 'a', 'Mark 10:47 — "And when he heard that it was Jesus of Nazareth, he began to cry out, and say, Jesus, thou Son of David, have mercy on me."'),
-- Adults
('Mark', 10, 'adults', 1, 'Why did Jesus say Moses permitted a bill of divorcement?', 'For the hardness of your hearts he wrote you this precept', 'Because marriage is temporary', 'Because divorce is God''s perfect will', 'Because Moses disliked marriage', 'a', 'Mark 10:5 — "And Jesus answered and said unto them, For the hardness of your heart he wrote you this precept."'),
('Mark', 10, 'adults', 2, 'What does Jesus say about receiving the kingdom of God like a child?', 'Whosoever shall not receive the kingdom of God as a little child, he shall not enter therein', 'Only literal children can enter the kingdom', 'Adults should act immature', 'Children are automatically saved', 'a', 'Mark 10:15 — "Verily I say unto you, Whosoever shall not receive the kingdom of God as a little child, he shall not enter therein."'),
('Mark', 10, 'adults', 3, 'What did the rich young ruler claim about keeping the commandments?', 'Master, all these have I observed from my youth', 'He admitted he had broken them all', 'He said he knew only a few', 'He asked which commandments Jesus meant', 'a', 'Mark 10:20 — "And he answered and said unto him, Master, all these have I observed from my youth."'),
('Mark', 10, 'adults', 4, 'How did Jesus feel when He looked at the rich young ruler?', 'He loved him — then told him to sell all he had, give to the poor, and follow Him', 'He was angry with him', 'He was indifferent', 'He was suspicious of his motives', 'a', 'Mark 10:21 — "Then Jesus beholding him loved him, and said unto him, One thing thou lackest: go thy way, sell whatsoever thou hast, and give to the poor."'),
('Mark', 10, 'adults', 5, 'What promise does Jesus make about those who leave everything for Him and the gospel?', 'They shall receive an hundredfold now in this time, and in the world to come eternal life', 'They will become wealthy immediately', 'They will suffer without reward', 'They will be forgotten by God', 'a', 'Mark 10:29-30 — "There is no man that hath left house, or brethren... but he shall receive an hundredfold now in this time... and in the world to come eternal life."'),
('Mark', 10, 'adults', 6, 'What does Jesus say the Son of man came to do?', 'Not to be ministered unto, but to minister, and to give his life a ransom for many', 'To be served by all nations', 'To establish an earthly kingdom', 'To overthrow the Roman Empire', 'a', 'Mark 10:45 — "For even the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many."'),
('Mark', 10, 'adults', 7, 'What "cup" and "baptism" does Jesus ask James and John about?', 'His suffering and death — the cup of God''s wrath and the baptism of His crucifixion', 'The communion cup and water baptism', 'A cup of wine and ritual washing', 'The cup of blessing and Spirit baptism', 'a', 'Mark 10:38 — "Can ye drink of the cup that I drink of? and be baptized with the baptism that I am baptized with?" The cup and baptism refer to His atoning death.'),
('Mark', 10, 'adults', 8, 'How does Mark 10:45 serve as a key verse summarizing Mark''s entire Gospel?', 'It encapsulates Jesus as the suffering Servant who came to serve and give His life as a substitutionary ransom — the central theme of Mark', 'It is a minor teaching among many', 'It only applies to the twelve disciples', 'It refers to a future, not present, mission', 'a', 'Mark 10:45 — "To give his life a ransom for many." This verse is often called the key verse of Mark, summarizing Jesus'' mission as the Servant-Redeemer (cf. Isaiah 53).');

-- ═══ Mark Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 11, 'kids', 1, 'What animal did Jesus ride into Jerusalem?', 'A young donkey (colt)', 'A horse', 'A camel', 'A chariot', 'a', 'Mark 11:7 — "And they brought the colt to Jesus, and cast their garments on him; and he sat upon him."'),
('Mark', 11, 'kids', 2, 'What did the people shout as Jesus entered Jerusalem?', 'Hosanna; Blessed is he that cometh in the name of the Lord', 'Go back to Nazareth', 'Hail Caesar', 'Long live the king of Rome', 'a', 'Mark 11:9 — "Hosanna; Blessed is he that cometh in the name of the Lord."'),
('Mark', 11, 'kids', 3, 'What did Jesus do to the money changers in the temple?', 'He overturned their tables and drove them out', 'He gave them more money', 'He sat down and talked with them', 'He invited them to dinner', 'a', 'Mark 11:15 — "And Jesus went into the temple, and began to cast out them that sold and bought in the temple, and overthrew the tables of the moneychangers."'),
-- Teens
('Mark', 11, 'teens', 1, 'What did Jesus find on the fig tree when He was hungry?', 'Nothing but leaves — it had no fruit', 'An abundance of figs', 'A bird''s nest', 'Beautiful flowers', 'a', 'Mark 11:13 — "And seeing a fig tree afar off having leaves, he came, if haply he might find any thing thereon: and when he came to it, he found nothing but leaves."'),
('Mark', 11, 'teens', 2, 'What did Jesus say the temple should be called?', 'A house of prayer for all nations', 'A house of business', 'A museum of ancient things', 'A place for priests only', 'a', 'Mark 11:17 — "Is it not written, My house shall be called of all nations the house of prayer? but ye have made it a den of thieves."'),
('Mark', 11, 'teens', 3, 'What happened to the fig tree the morning after Jesus cursed it?', 'It was dried up from the roots', 'It grew more leaves', 'It produced fruit', 'Nothing changed', 'a', 'Mark 11:20 — "And in the morning, as they passed by, they saw the fig tree dried up from the roots."'),
('Mark', 11, 'teens', 4, 'What did Jesus teach about prayer using the fig tree as an example?', 'Whatever you ask in prayer, believe that you receive it, and you shall have it', 'Prayer only works in the temple', 'Only priests can have effective prayers', 'Prayer is not really necessary', 'a', 'Mark 11:24 — "What things soever ye desire, when ye pray, believe that ye receive them, and ye shall have them."'),
('Mark', 11, 'teens', 5, 'What condition did Jesus add about forgiveness and prayer?', 'When ye stand praying, forgive, if ye have ought against any, that your Father may forgive you', 'Forgiveness is not connected to prayer', 'Only forgive those who ask', 'God forgives everyone automatically', 'a', 'Mark 11:25 — "And when ye stand praying, forgive, if ye have ought against any: that your Father also which is in heaven may forgive you your trespasses."'),
-- Adults
('Mark', 11, 'adults', 1, 'What Old Testament prophecy did Jesus fulfill by riding into Jerusalem on a colt?', 'Zechariah 9:9 — "Thy King cometh unto thee... lowly, and riding upon an ass, and upon a colt the foal of an ass"', 'Isaiah 53 — the suffering servant', 'Malachi 3:1 — the messenger', 'Daniel 7:13 — the Son of man coming in clouds', 'a', 'Mark 11:7,9 — Jesus'' entry on a colt fulfills Zechariah 9:9, presenting Himself as the humble, peaceful Messianic King.'),
('Mark', 11, 'adults', 2, 'What does the cursing of the fig tree symbolize?', 'God''s judgment on Israel for having the appearance of spiritual life (leaves) but bearing no fruit of genuine faith', 'That fig trees are inferior to other trees', 'That Jesus was unreasonably angry', 'That agriculture was failing in Palestine', 'a', 'Mark 11:13-14,20 — The fig tree with leaves but no fruit symbolizes Israel''s religious show without genuine righteousness. Its withering foreshadows judgment on the temple.'),
('Mark', 11, 'adults', 3, 'How does the temple cleansing narrative bracket the fig tree episode (Mark 11:12-21)?', 'Mark uses a "sandwich" literary structure: fig tree cursed (A), temple cleansed (B), fig tree withered (A'') — linking fruitlessness to temple corruption', 'The events are completely unrelated', 'The fig tree episode was an afterthought', 'Mark simply recorded events chronologically', 'a', 'Mark 11:12-21 — Mark''s intercalation (sandwich) technique links the barren fig tree to the corrupt temple, both judged for outward show without genuine devotion.'),
('Mark', 11, 'adults', 4, 'What Scripture quotation does Jesus combine when cleansing the temple?', 'Isaiah 56:7 ("My house shall be called of all nations the house of prayer") and Jeremiah 7:11 ("a den of thieves")', 'Psalm 23 and Proverbs 3', 'Genesis 1 and Exodus 20', 'Deuteronomy 6 and Leviticus 19', 'a', 'Mark 11:17 — Jesus merges Isaiah 56:7 with Jeremiah 7:11, condemning the exploitation of worshippers and exclusion of Gentiles from the temple courts.'),
('Mark', 11, 'adults', 5, 'What does Jesus'' saying about moving a mountain into the sea illustrate?', 'The extraordinary power available through faith-filled prayer — nothing is impossible for God', 'That literal mountains should be moved', 'That prayer replaces physical action', 'That geography is meaningless to God', 'a', 'Mark 11:23 — "Whosoever shall say unto this mountain, Be thou removed, and be thou cast into the sea; and shall not doubt in his heart... he shall have whatsoever he saith."'),
('Mark', 11, 'adults', 6, 'How did Jesus respond when the chief priests asked by what authority He acted?', 'He counter-questioned them about the baptism of John — whether it was from heaven or of men', 'He showed them a written decree', 'He performed a miracle as proof', 'He quoted the Law of Moses', 'a', 'Mark 11:29-30 — "I will also ask of you one question... The baptism of John, was it from heaven, or of men?"'),
('Mark', 11, 'adults', 7, 'Why could the chief priests not answer Jesus'' question about John''s baptism?', 'If they said from heaven, Jesus would ask why they did not believe John; if from men, they feared the people', 'They did not know who John was', 'They had not considered the question', 'They were forbidden to discuss baptism', 'a', 'Mark 11:31-32 — "If we shall say, From heaven; he will say, Why then did ye not believe him? But if we shall say, Of men; they feared the people."'),
('Mark', 11, 'adults', 8, 'What is the theological significance of "Hosanna in the highest" and "Blessed is he that cometh in the name of the Lord"?', 'The crowd quotes Psalm 118:25-26, a Messianic psalm used during Passover, recognizing Jesus as the long-awaited Davidic King', 'It was a common greeting for any visitor', 'The people were merely following Roman custom', 'The words had no special religious meaning', 'a', 'Mark 11:9-10 — "Hosanna; Blessed is he that cometh in the name of the Lord: Blessed be the kingdom of our father David." Psalm 118 was a Hallel psalm with Messianic expectations.');

-- ═══ Mark Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 12, 'kids', 1, 'In Jesus'' story, what did the wicked farmers do to the owner''s son?', 'They killed him', 'They welcomed him', 'They ignored him', 'They hired him', 'a', 'Mark 12:7-8 — "This is the heir; come, let us kill him... And they took him, and killed him, and cast him out of the vineyard."'),
('Mark', 12, 'kids', 2, 'What is the greatest commandment according to Jesus?', 'Love the Lord thy God with all thy heart, soul, mind, and strength', 'Do not steal', 'Keep the sabbath', 'Honour thy father and mother', 'a', 'Mark 12:30 — "And thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind, and with all thy strength."'),
('Mark', 12, 'kids', 3, 'What did the poor widow put into the temple treasury?', 'Two small coins (mites)', 'A bag of gold', 'Ten silver coins', 'A precious stone', 'a', 'Mark 12:42 — "And there came a certain poor widow, and she threw in two mites, which make a farthing."'),
-- Teens
('Mark', 12, 'teens', 1, 'How did Jesus answer the trick question about paying taxes to Caesar?', 'Render to Caesar the things that are Caesar''s, and to God the things that are God''s', 'Do not pay any taxes', 'Pay double taxes to show obedience', 'Taxes are sinful', 'a', 'Mark 12:17 — "Render to Caesar the things that are Caesar''s, and to God the things that are God''s."'),
('Mark', 12, 'teens', 2, 'What did the Sadducees try to trick Jesus with?', 'A question about the resurrection involving a woman married to seven brothers', 'A question about the sabbath', 'A question about fasting', 'A question about clean and unclean foods', 'a', 'Mark 12:23 — "In the resurrection therefore, when they shall rise, whose wife shall she be of them? for the seven had her to wife."'),
('Mark', 12, 'teens', 3, 'What did Jesus say about marriage in the resurrection?', 'They neither marry nor are given in marriage but are as the angels in heaven', 'Marriage continues in heaven', 'Only the first marriage counts', 'There is no resurrection', 'a', 'Mark 12:25 — "For when they shall rise from the dead, they neither marry, nor are given in marriage; but are as the angels which are in heaven."'),
('Mark', 12, 'teens', 4, 'What is the second greatest commandment?', 'Thou shalt love thy neighbour as thyself', 'Thou shalt not steal', 'Remember the sabbath day', 'Thou shalt not kill', 'a', 'Mark 12:31 — "And the second is like, namely this, Thou shalt love thy neighbour as thyself."'),
('Mark', 12, 'teens', 5, 'Why did Jesus say the widow gave more than all the rich people?', 'She gave all she had to live on, while they gave out of their abundance', 'She gave a larger amount', 'She gave more frequently', 'She gave the most beautiful coins', 'a', 'Mark 12:44 — "For all they did cast in of their abundance; but she of her want did cast in all that she had, even all her living."'),
-- Adults
('Mark', 12, 'adults', 1, 'Who does the "beloved son" represent in the parable of the wicked husbandmen?', 'Jesus Christ — sent by God the Father (the householder) to Israel (the vineyard), and killed by the religious leaders (the husbandmen)', 'Any generic prophet', 'John the Baptist', 'King David', 'a', 'Mark 12:6-8 — "Having yet therefore one son, his wellbeloved, he sent him also last unto them, saying, They will reverence my son. But those husbandmen said... let us kill him."'),
('Mark', 12, 'adults', 2, 'What Scripture does Jesus quote after the parable of the wicked husbandmen?', 'The stone which the builders rejected is become the head of the corner — Psalm 118:22-23', 'The Lord is my shepherd — Psalm 23:1', 'In the beginning God created — Genesis 1:1', 'The fear of the Lord is the beginning of wisdom — Proverbs 9:10', 'a', 'Mark 12:10-11 — "The stone which the builders rejected is become the head of the corner: This was the Lord''s doing, and it is marvellous in our eyes."'),
('Mark', 12, 'adults', 3, 'How did Jesus prove the resurrection to the Sadducees from the Torah?', 'He quoted Exodus 3:6 — God said "I am the God of Abraham, Isaac, and Jacob," not "I was" — He is God of the living, not the dead', 'He quoted Daniel''s vision of the resurrection', 'He pointed to Elijah raising the dead', 'He cited the story of Lazarus', 'a', 'Mark 12:26-27 — "I am the God of Abraham, and the God of Isaac, and the God of Jacob? He is not the God of the dead, but the God of the living."'),
('Mark', 12, 'adults', 4, 'What did the scribe say when Jesus gave the two great commandments?', 'That to love God and neighbor is more than all whole burnt offerings and sacrifices', 'That Jesus was wrong', 'That the commandments cannot be ranked', 'That sacrifice is more important than love', 'a', 'Mark 12:33 — "And to love him with all the heart... and to love his neighbour as himself, is more than all whole burnt offerings and sacrifices."'),
('Mark', 12, 'adults', 5, 'What did Jesus say to the scribe who answered wisely?', 'Thou art not far from the kingdom of God', 'You are already in the kingdom', 'You are very far from truth', 'You need to fast more', 'a', 'Mark 12:34 — "And when Jesus saw that he answered discreetly, he said unto him, Thou art not far from the kingdom of God."'),
('Mark', 12, 'adults', 6, 'What question did Jesus raise about David and the Messiah using Psalm 110?', 'If David calls the Messiah "Lord," how is He then merely David''s son? — pointing to the Messiah''s divinity', 'He asked why David was a shepherd', 'He questioned David''s right to be king', 'He asked why David wrote psalms', 'a', 'Mark 12:37 — "David therefore himself calleth him Lord; and whence is he then his son?" Jesus uses Psalm 110:1 to show the Messiah is both David''s descendant and David''s Lord.'),
('Mark', 12, 'adults', 7, 'What did Jesus warn about the scribes?', 'They love long robes, chief seats, and long prayers, but devour widows'' houses — they shall receive greater damnation', 'They are humble servants', 'They are the most righteous people', 'They deserve honor above all', 'a', 'Mark 12:38-40 — "Beware of the scribes, which love to go in long clothing, and love salutations... and for a pretence make long prayers: these shall receive greater damnation."'),
('Mark', 12, 'adults', 8, 'What principle about giving does the widow''s mites episode teach?', 'God evaluates giving not by the amount but by the sacrifice — the widow gave proportionally more because she gave everything she had', 'That only small donations please God', 'That the temple treasury was poorly managed', 'That widows should not give to the temple', 'a', 'Mark 12:43-44 — "This poor widow hath cast more in, than all they which have cast into the treasury: For all they did cast in of their abundance; but she of her want did cast in all that she had."');

-- ═══════════════ CHAPTERS 13–16 ═══════════════

-- ═══ Mark Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 13, 'kids', 1, 'What did Jesus say would happen to the temple?', 'Not one stone would be left upon another — it would all be thrown down', 'It would last forever', 'It would become even bigger', 'It would float into the sky', 'a', 'Mark 13:2 — "Seest thou these great buildings? there shall not be left one stone upon another, that shall not be thrown down."'),
('Mark', 13, 'kids', 2, 'What did Jesus say about false Christs?', 'Many shall come saying I am Christ, but do not believe them', 'No one would ever pretend to be Christ', 'Only one false Christ would appear', 'False Christs would help people', 'a', 'Mark 13:6 — "For many shall come in my name, saying, I am Christ; and shall deceive many."'),
('Mark', 13, 'kids', 3, 'What did Jesus tell His followers to do?', 'Watch and be ready', 'Sleep and rest', 'Run away and hide', 'Build a fort', 'a', 'Mark 13:37 — "And what I say unto you I say unto all, Watch."'),
-- Teens
('Mark', 13, 'teens', 1, 'What signs did Jesus give before the end?', 'Wars, earthquakes, famines, and persecution — but the gospel must first be published among all nations', 'Only peace and prosperity', 'Nothing unusual would happen', 'The stars would dance', 'a', 'Mark 13:7-10 — "And when ye shall hear of wars and rumours of wars, be ye not troubled... and the gospel must first be published among all nations."'),
('Mark', 13, 'teens', 2, 'What did Jesus say about the "abomination of desolation"?', 'When ye shall see it standing where it ought not, let those in Judaea flee to the mountains', 'It refers to a beautiful new statue', 'It is a natural disaster', 'It describes a solar eclipse', 'a', 'Mark 13:14 — "But when ye shall see the abomination of desolation, spoken of by Daniel the prophet, standing where it ought not... then let them that be in Judaea flee to the mountains."'),
('Mark', 13, 'teens', 3, 'How will the Son of man come according to Jesus?', 'In the clouds with great power and glory', 'Walking on the road', 'Riding a horse', 'Appearing in the temple', 'a', 'Mark 13:26 — "And then shall they see the Son of man coming in the clouds with great power and glory."'),
('Mark', 13, 'teens', 4, 'What did Jesus say about heaven and earth?', 'Heaven and earth shall pass away, but my words shall not pass away', 'Heaven and earth are eternal', 'His words would eventually be forgotten', 'Only heaven would remain', 'a', 'Mark 13:31 — "Heaven and earth shall pass away: but my words shall not pass away."'),
('Mark', 13, 'teens', 5, 'Does anyone know the day and hour of Christ''s return?', 'No, not even the angels in heaven, nor the Son, but only the Father', 'The prophets know the exact date', 'It was revealed to the apostles', 'It can be calculated from Scripture', 'a', 'Mark 13:32 — "But of that day and that hour knoweth no man, no, not the angels which are in heaven, neither the Son, but the Father."'),
-- Adults
('Mark', 13, 'adults', 1, 'Which four disciples asked Jesus privately about the destruction of the temple?', 'Peter, James, John, and Andrew', 'Peter, James, John, and Matthew', 'Peter, Andrew, Philip, and Thomas', 'James, John, Judas, and Bartholomew', 'a', 'Mark 13:3 — "And as he sat upon the mount of Olives over against the temple, Peter and James and John and Andrew asked him privately."'),
('Mark', 13, 'adults', 2, 'What does Jesus promise the Holy Spirit will do when believers are brought before rulers?', 'It is not ye that speak, but the Holy Ghost — He will give them the words to say', 'They should memorize speeches in advance', 'They should hire lawyers to defend them', 'They should remain silent in court', 'a', 'Mark 13:11 — "But when they shall lead you, and deliver you up, take no thought beforehand what ye shall speak... for it is not ye that speak, but the Holy Ghost."'),
('Mark', 13, 'adults', 3, 'What does "the abomination of desolation spoken of by Daniel the prophet" refer to historically and prophetically?', 'It references Daniel 9:27 and 12:11 — historically fulfilled in the Roman destruction of the temple (AD 70) and potentially pointing to a future end-time desecration', 'It refers only to Antiochus Epiphanes', 'It was fulfilled entirely in the Babylonian exile', 'It has no specific historical referent', 'a', 'Mark 13:14 — "The abomination of desolation, spoken of by Daniel the prophet." This echoes Daniel 9:27 and was partially fulfilled in AD 70 when Rome destroyed the temple.'),
('Mark', 13, 'adults', 4, 'What does Jesus say about the tribulation in verse 19?', 'It will be the worst affliction since the creation until now, and never shall be again', 'It will be a time of moderate difficulty', 'It will be shorter than previous trials', 'It will affect only Gentiles', 'a', 'Mark 13:19 — "For in those days shall be affliction, such as was not from the beginning of the creation which God created unto this time, neither shall be."'),
('Mark', 13, 'adults', 5, 'For whose sake did Jesus say those days would be shortened?', 'The elect''s sake, whom He hath chosen', 'The Roman emperor''s sake', 'The high priest''s sake', 'The sake of the angels', 'a', 'Mark 13:20 — "And except that the Lord had shortened those days, no flesh should be saved: but for the elect''s sake, whom he hath chosen, he hath shortened the days."'),
('Mark', 13, 'adults', 6, 'What cosmic signs will accompany the Son of man''s coming?', 'The sun shall be darkened, the moon shall not give her light, the stars shall fall, and the powers in heaven shall be shaken', 'A great rainbow will appear', 'The seas will turn to glass', 'All mountains will crumble', 'a', 'Mark 13:24-25 — "But in those days, after that tribulation, the sun shall be darkened, and the moon shall not give her light, And the stars of heaven shall fall, and the powers that are in heaven shall be shaken."'),
('Mark', 13, 'adults', 7, 'What parable does Jesus use to illustrate watchfulness at the end of chapter 13?', 'The parable of the man travelling to a far country who left his servants in charge, commanding the porter to watch', 'The parable of the ten virgins', 'The parable of the talents', 'The parable of the wheat and tares', 'a', 'Mark 13:34 — "For the Son of man is as a man taking a far journey, who left his house, and gave authority to his servants, and to every man his work, and commanded the porter to watch."'),
('Mark', 13, 'adults', 8, 'How does Jesus'' statement that "neither the Son" knows the day and hour relate to His dual nature?', 'In His human nature, Jesus voluntarily limited His omniscience; as God the Son, all things are known to Him — this reflects the mystery of the incarnation', 'It proves Jesus is not truly divine', 'It means Jesus is inferior to the Father', 'It was simply a figure of speech', 'a', 'Mark 13:32 — "Neither the Son, but the Father." This is understood as reflecting Christ''s voluntary self-limitation in His incarnate state (cf. Philippians 2:7).');

-- ═══ Mark Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 14, 'kids', 1, 'What did the woman pour on Jesus'' head?', 'Very precious ointment (spikenard)', 'Water', 'Oil for cooking', 'Honey', 'a', 'Mark 14:3 — "There came a woman having an alabaster box of ointment of spikenard very precious; and she brake the box, and poured it on his head."'),
('Mark', 14, 'kids', 2, 'What did Jesus share with His disciples at the Last Supper?', 'Bread and wine, saying the bread was His body and the wine His blood', 'Fish and bread', 'Lamb and vegetables', 'Water and fruit', 'a', 'Mark 14:22-24 — "Take, eat: this is my body... This is my blood of the new testament, which is shed for many."'),
('Mark', 14, 'kids', 3, 'How did Judas show the soldiers which man was Jesus?', 'He kissed Jesus', 'He pointed at Him', 'He called His name', 'He threw a stone', 'a', 'Mark 14:44-45 — "Whomsoever I shall kiss, that same is he... and kissed him."'),
-- Teens
('Mark', 14, 'teens', 1, 'How much was the woman''s ointment worth?', 'More than three hundred pence (nearly a year''s wages)', 'Ten pence', 'Fifty pence', 'One thousand pence', 'a', 'Mark 14:5 — "For it might have been sold for more than three hundred pence, and have been given to the poor."'),
('Mark', 14, 'teens', 2, 'What did Jesus predict Peter would do?', 'Deny Him three times before the cock crew twice', 'Defend Him with a sword', 'Run away and never return', 'Betray Him for money', 'a', 'Mark 14:30 — "Verily I say unto thee, That this day, even in this night, before the cock crow twice, thou shalt deny me thrice."'),
('Mark', 14, 'teens', 3, 'What did Jesus pray in the Garden of Gethsemane?', 'Abba, Father, all things are possible unto thee; take away this cup from me: nevertheless not what I will, but what thou wilt', 'Let me escape from my enemies', 'Destroy those who oppose me', 'Send angels to protect me from all harm', 'a', 'Mark 14:36 — "Abba, Father, all things are possible unto thee; take away this cup from me: nevertheless not what I will, but what thou wilt."'),
('Mark', 14, 'teens', 4, 'What did the disciples do when Jesus was arrested?', 'They all forsook Him and fled', 'They fought the soldiers bravely', 'They followed Him to the trial', 'They negotiated His release', 'a', 'Mark 14:50 — "And they all forsook him, and fled."'),
('Mark', 14, 'teens', 5, 'What happened when Peter was accused of being with Jesus?', 'He denied it three times, and then the cock crew and he wept', 'He boldly confessed Jesus', 'He ran away immediately', 'He stayed silent', 'a', 'Mark 14:72 — "And the second time the cock crew. And Peter called to mind the word that Jesus said unto him... And when he thought thereon, he wept."'),
-- Adults
('Mark', 14, 'adults', 1, 'What did Jesus say about the woman who anointed Him?', 'She is come aforehand to anoint my body to the burying — and wherever the gospel is preached, her deed shall be told as a memorial', 'She wasted expensive ointment', 'She should have given to the poor instead', 'Her act was merely symbolic', 'a', 'Mark 14:8-9 — "She is come aforehand to anoint my body to the burying. Verily I say unto you, Wheresoever this gospel shall be preached throughout the whole world, this also that she hath done shall be spoken of for a memorial of her."'),
('Mark', 14, 'adults', 2, 'How much did Judas receive for betraying Jesus?', 'The chief priests promised him money — Mark does not specify the amount, but Matthew 26:15 records thirty pieces of silver', 'One hundred gold coins', 'Nothing — he did it freely', 'A piece of land', 'a', 'Mark 14:10-11 — "And Judas Iscariot, one of the twelve, went unto the chief priests, to betray him unto them... and they promised to give him money."'),
('Mark', 14, 'adults', 3, 'What words did Jesus use to institute the Lord''s Supper?', 'Take, eat: this is my body... This is my blood of the new testament, which is shed for many', 'Let us eat in remembrance of Moses', 'This food shall sustain you forever', 'Break bread and share with strangers', 'a', 'Mark 14:22,24 — "Take, eat: this is my body... This is my blood of the new testament, which is shed for many."'),
('Mark', 14, 'adults', 4, 'What does Jesus'' use of "Abba" in Gethsemane reveal?', 'An intimate Aramaic term for Father, revealing Christ''s unique filial relationship with God even in His deepest anguish', 'A formal title used by all Jews', 'A Greek philosophical concept', 'A term meaning "teacher"', 'a', 'Mark 14:36 — "Abba, Father." Abba is an intimate Aramaic address, showing Jesus'' tender, trusting relationship with the Father even facing the cross.'),
('Mark', 14, 'adults', 5, 'What claim did Jesus make before the high priest that was declared blasphemy?', 'When asked if He was the Christ, the Son of the Blessed, Jesus said "I am" and quoted Daniel 7:13 about the Son of man sitting at the right hand of power', 'He claimed to be an angel', 'He said He was greater than Moses', 'He declared the temple would be rebuilt in three days', 'a', 'Mark 14:61-62 — "Art thou the Christ, the Son of the Blessed? And Jesus said, I am: and ye shall see the Son of man sitting on the right hand of power, and coming in the clouds of heaven."'),
('Mark', 14, 'adults', 6, 'What detail unique to Mark describes a young man who fled naked at Jesus'' arrest?', 'A young man wearing only a linen cloth was seized; he left the cloth and fled naked — many scholars believe this was Mark himself', 'A soldier lost his uniform', 'Peter threw off his cloak', 'An angel appeared and vanished', 'a', 'Mark 14:51-52 — "And there followed him a certain young man, having a linen cloth cast about his naked body; and the young men laid hold on him: And he left the linen cloth, and fled from them naked."'),
('Mark', 14, 'adults', 7, 'What does Jesus'' statement "I am" (ego eimi) before the Sanhedrin echo?', 'The divine name revealed to Moses at the burning bush (Exodus 3:14) — "I AM THAT I AM" — a direct claim to deity', 'A common Greek greeting', 'An acknowledgment of His human identity', 'A phrase used by all Jewish teachers', 'a', 'Mark 14:62 — "I am." Jesus'' use of "I am" (ego eimi) in response to the question of His identity deliberately echoes the divine self-revelation of Exodus 3:14.'),
('Mark', 14, 'adults', 8, 'How does Peter''s denial fulfill Jesus'' prophecy and what does the cock crowing twice signify?', 'Jesus predicted the specific detail of two cock-crows (unique to Mark), showing His foreknowledge; Peter''s failure under pressure contrasts with his earlier boast of loyalty', 'The rooster crowing was coincidental', 'Peter denied Jesus only once', 'The cock crowing was a metaphor for morning', 'a', 'Mark 14:30,72 — "Before the cock crow twice, thou shalt deny me thrice." Mark alone records the two cock-crows, a precise detail suggesting Peter''s own eyewitness testimony as Mark''s source.');

-- ═══ Mark Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 15, 'kids', 1, 'Who did the crowd choose to set free instead of Jesus?', 'Barabbas', 'Peter', 'Lazarus', 'Paul', 'a', 'Mark 15:11,15 — "But the chief priests moved the people, that he should rather release Barabbas unto them... And so Pilate, willing to content the people, released Barabbas unto them."'),
('Mark', 15, 'kids', 2, 'What did the soldiers put on Jesus'' head?', 'A crown of thorns', 'A golden crown', 'A wreath of flowers', 'A hat', 'a', 'Mark 15:17 — "And they clothed him with purple, and platted a crown of thorns, and put it about his head."'),
('Mark', 15, 'kids', 3, 'Who asked Pilate for Jesus'' body to bury it?', 'Joseph of Arimathaea', 'Peter', 'John', 'Nicodemus', 'a', 'Mark 15:43 — "Joseph of Arimathaea, an honourable counsellor... went in boldly unto Pilate, and craved the body of Jesus."'),
-- Teens
('Mark', 15, 'teens', 1, 'What did Pilate ask Jesus, and how did Jesus respond?', 'Pilate asked "Art thou the King of the Jews?" and Jesus answered "Thou sayest it"', 'Pilate asked "Are you guilty?" and Jesus said "No"', 'Pilate asked "Do you know God?" and Jesus preached a sermon', 'Pilate asked nothing and condemned Him immediately', 'a', 'Mark 15:2 — "And Pilate asked him, Art thou the King of the Jews? And he answering said unto him, Thou sayest it."'),
('Mark', 15, 'teens', 2, 'Who was compelled to carry Jesus'' cross?', 'Simon of Cyrene, the father of Alexander and Rufus', 'Peter the disciple', 'A Roman soldier', 'John the Baptist''s disciple', 'a', 'Mark 15:21 — "And they compel one Simon a Cyrenian, who passed by, coming out of the country, the father of Alexander and Rufus, to bear his cross."'),
('Mark', 15, 'teens', 3, 'What happened from the sixth hour to the ninth hour (noon to 3 PM)?', 'There was darkness over the whole land', 'There was a great earthquake', 'A rainbow appeared', 'The sun shone brighter than ever', 'a', 'Mark 15:33 — "And when the sixth hour was come, there was darkness over the whole land until the ninth hour."'),
('Mark', 15, 'teens', 4, 'What did Jesus cry out at the ninth hour?', 'Eloi, Eloi, lama sabachthani — My God, my God, why hast thou forsaken me?', 'Father, forgive them', 'It is finished', 'Into thy hands I commend my spirit', 'a', 'Mark 15:34 — "And at the ninth hour Jesus cried with a loud voice, saying, Eloi, Eloi, lama sabachthani? which is, being interpreted, My God, my God, why hast thou forsaken me?"'),
('Mark', 15, 'teens', 5, 'What happened in the temple when Jesus died?', 'The veil of the temple was rent in twain from the top to the bottom', 'The altar caught fire', 'The doors of the temple opened', 'The temple bells rang by themselves', 'a', 'Mark 15:38 — "And the veil of the temple was rent in twain from the top to the bottom."'),
-- Adults
('Mark', 15, 'adults', 1, 'What did Pilate marvel at regarding Jesus during the trial?', 'That Jesus answered nothing to the many accusations against Him', 'That Jesus spoke so eloquently', 'That Jesus performed a miracle', 'That Jesus was dressed in fine clothing', 'a', 'Mark 15:5 — "But Jesus yet answered nothing; so that Pilate marvelled."'),
('Mark', 15, 'adults', 2, 'What does the release of Barabbas (a murderer) instead of Jesus illustrate theologically?', 'The innocent dying in the place of the guilty — a vivid picture of substitutionary atonement', 'That the Jewish legal system was fair', 'That Barabbas was innocent', 'That crowds make good decisions', 'a', 'Mark 15:7,15 — Barabbas, a murderer, was released while the innocent Jesus was condemned — a powerful illustration of the gospel: Christ takes the sinner''s place.'),
('Mark', 15, 'adults', 3, 'What is the significance of Jesus'' cry "Eloi, Eloi, lama sabachthani?"', 'It quotes Psalm 22:1, showing Jesus bore the full weight of divine judgment for sin, experiencing separation from the Father on behalf of humanity', 'It shows Jesus lost faith on the cross', 'It was an appeal to Elijah for help', 'It was a prayer for physical relief', 'a', 'Mark 15:34 — "My God, my God, why hast thou forsaken me?" quotes Psalm 22:1. Jesus experienced the spiritual agony of bearing the world''s sin (2 Corinthians 5:21).'),
('Mark', 15, 'adults', 4, 'What does the tearing of the temple veil from top to bottom signify?', 'God Himself opened access to His presence — the barrier between God and man was removed through Christ''s atoning death', 'An earthquake caused structural damage', 'The priests tore it in grief', 'It was old and simply wore out', 'a', 'Mark 15:38 — "And the veil of the temple was rent in twain from the top to the bottom." The direction (top to bottom) signifies divine action, not human; access to God is now open (Hebrews 10:19-20).'),
('Mark', 15, 'adults', 5, 'What did the Roman centurion say when he saw how Jesus died?', 'Truly this man was the Son of God', 'This was just another criminal', 'He deserved what he got', 'His followers will cause trouble', 'a', 'Mark 15:39 — "And when the centurion, which stood over against him, saw that he so cried out, and gave up the ghost, he said, Truly this man was the Son of God."'),
('Mark', 15, 'adults', 6, 'Why is the centurion''s confession in Mark 15:39 theologically significant?', 'A Gentile soldier recognizes what Israel''s leaders rejected — Jesus is the Son of God — echoing Mark 1:1 and forming an inclusio for the entire Gospel', 'It shows that Roman soldiers were secret Christians', 'It proves that execution methods were humane', 'It demonstrates military respect for prisoners', 'a', 'Mark 15:39 — "Truly this man was the Son of God." This confession by a Gentile bookends Mark''s opening (1:1) and shows that the cross, not miracles, ultimately reveals Jesus'' identity.'),
('Mark', 15, 'adults', 7, 'Which women does Mark name as watching the crucifixion from afar?', 'Mary Magdalene, Mary the mother of James the less and of Joses, and Salome', 'Mary the mother of Jesus and Martha', 'Joanna and Susanna', 'Elizabeth and Anna', 'a', 'Mark 15:40 — "There were also women looking on afar off: among whom was Mary Magdalene, and Mary the mother of James the less and of Joses, and Salome."'),
('Mark', 15, 'adults', 8, 'What details does Mark provide about Joseph of Arimathaea that show the significance of his action?', 'He was an honourable counsellor who also waited for the kingdom of God, went boldly to Pilate, bought fine linen, and laid Jesus in a hewn rock tomb', 'He was a poor man with no resources', 'He was a Roman citizen with political motives', 'He was one of the twelve disciples', 'a', 'Mark 15:43-46 — Joseph was a member of the Sanhedrin who risked his reputation and safety by publicly requesting Jesus'' body for burial, fulfilling Isaiah 53:9.');

-- ═══ Mark Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 16, 'kids', 1, 'When the women came to the tomb, what did they find?', 'The stone was rolled away and the tomb was empty', 'Jesus was still inside', 'The soldiers were guarding it', 'The tomb was sealed shut', 'a', 'Mark 16:4 — "And when they looked, they saw that the stone was rolled away: for it was very great."'),
('Mark', 16, 'kids', 2, 'What did the young man in white tell the women?', 'Jesus is risen; He is not here', 'Jesus is still sleeping', 'Come back tomorrow', 'You have the wrong tomb', 'a', 'Mark 16:6 — "And he saith unto them, Be not affrighted: Ye seek Jesus of Nazareth, which was crucified: he is risen; he is not here."'),
('Mark', 16, 'kids', 3, 'What did Jesus tell His disciples to do before He went to heaven?', 'Go into all the world and preach the gospel to every creature', 'Stay in Jerusalem forever', 'Write books about Him', 'Build a new temple', 'a', 'Mark 16:15 — "And he said unto them, Go ye into all the world, and preach the gospel to every creature."'),
-- Teens
('Mark', 16, 'teens', 1, 'Who came to the tomb very early on the first day of the week?', 'Mary Magdalene, Mary the mother of James, and Salome', 'Peter, James, and John', 'The twelve disciples', 'Nicodemus and Joseph', 'a', 'Mark 16:1-2 — "And when the sabbath was past, Mary Magdalene, and Mary the mother of James, and Salome... came unto the sepulchre at the rising of the sun."'),
('Mark', 16, 'teens', 2, 'What were the women worried about on the way to the tomb?', 'Who shall roll us away the stone from the door of the sepulchre?', 'Whether the soldiers would stop them', 'Whether they had enough spices', 'Whether the tomb was the right one', 'a', 'Mark 16:3 — "And they said among themselves, Who shall roll us away the stone from the door of the sepulchre?"'),
('Mark', 16, 'teens', 3, 'To whom did Jesus first appear after His resurrection?', 'Mary Magdalene, out of whom He had cast seven devils', 'Peter the apostle', 'John the beloved disciple', 'His mother Mary', 'a', 'Mark 16:9 — "Now when Jesus was risen early the first day of the week, he appeared first to Mary Magdalene, out of whom he had cast seven devils."'),
('Mark', 16, 'teens', 4, 'What did Jesus say would follow those who believe?', 'Signs: casting out devils, speaking with new tongues, and taking up serpents without harm', 'Wealth and prosperity', 'Freedom from all suffering', 'Immediate entry to heaven', 'a', 'Mark 16:17 — "And these signs shall follow them that believe; In my name shall they cast out devils; they shall speak with new tongues."'),
('Mark', 16, 'teens', 5, 'Where did Jesus go after speaking to His disciples?', 'He was received up into heaven and sat on the right hand of God', 'He went to Egypt', 'He returned to Nazareth', 'He traveled to Rome', 'a', 'Mark 16:19 — "So then after the Lord had spoken unto them, he was received up into heaven, and sat on the right hand of God."'),
-- Adults
('Mark', 16, 'adults', 1, 'What instructions did the young man in white give the women?', 'Go tell His disciples and Peter that He goeth before you into Galilee; there shall ye see Him', 'Stay here and wait for further instructions', 'Go to the temple and offer sacrifice', 'Return home and tell no one', 'a', 'Mark 16:7 — "But go your way, tell his disciples and Peter that he goeth before you into Galilee: there shall ye see him, as he said unto you."'),
('Mark', 16, 'adults', 2, 'Why is the specific mention of "and Peter" in verse 7 significant?', 'It shows grace to the one who had denied Christ three times — Peter is personally named to assure him he is not excluded from restoration', 'Peter was the leader so he naturally came first', 'Peter lived the closest to the tomb', 'It was an administrative instruction', 'a', 'Mark 16:7 — "Tell his disciples and Peter." After his denials, Peter might have considered himself disqualified; the specific mention of his name is a message of personal grace and restoration.'),
('Mark', 16, 'adults', 3, 'What is the textual significance of Mark 16:9-20?', 'These verses (the "longer ending") are absent from the two oldest Greek manuscripts (Sinaiticus and Vaticanus) and are debated by scholars, though accepted in the KJV tradition', 'All manuscripts contain these verses identically', 'These verses were added in the 20th century', 'Only Catholic manuscripts include them', 'a', 'Mark 16:9-20 — The longer ending of Mark is present in the KJV and most manuscripts but absent from Codex Sinaiticus and Vaticanus. Scholars debate its originality.'),
('Mark', 16, 'adults', 4, 'What does the Great Commission in Mark 16:15-16 emphasize compared to Matthew 28:19-20?', 'Mark emphasizes believing and being baptized for salvation, with condemnation for unbelief — focusing on individual response to the gospel', 'Mark focuses on making disciples of nations', 'Mark emphasizes teaching commandments', 'Mark is identical to Matthew''s version', 'a', 'Mark 16:15-16 — "He that believeth and is baptized shall be saved; but he that believeth not shall be damned." Mark''s version stresses personal belief and its eternal consequences.'),
('Mark', 16, 'adults', 5, 'How does the ending of Mark''s Gospel at verse 8 create a literary effect if taken as the original ending?', 'The abrupt ending — "for they were afraid" — leaves the reader to respond personally to the resurrection, creating an open-ended call to faith and action', 'Mark simply ran out of papyrus', 'The ending was accidentally lost', 'Mark intended to write a sequel', 'a', 'Mark 16:8 — "And they went out quickly, and fled from the sepulchre; for they trembled and were amazed: neither said they any thing to any man; for they were afraid." If original, this ending confronts the reader with the resurrection and demands a personal response.'),
('Mark', 16, 'adults', 6, 'What does Jesus'' ascension and sitting at the right hand of God signify?', 'His exaltation, completion of His redemptive work, and present intercessory authority as King and High Priest', 'He retired from active ministry', 'He is waiting passively until the end', 'He surrendered His power to the Father', 'a', 'Mark 16:19 — "He was received up into heaven, and sat on the right hand of God." The right hand signifies authority and honor (cf. Psalm 110:1, Hebrews 1:3).'),
('Mark', 16, 'adults', 7, 'What does the final verse of Mark say about the disciples'' subsequent ministry?', 'They went forth and preached every where, the Lord working with them and confirming the word with signs following', 'They stayed in Jerusalem and never traveled', 'They wrote books but did not preach', 'They returned to their former occupations', 'a', 'Mark 16:20 — "And they went forth, and preached every where, the Lord working with them, and confirming the word with signs following."'),
('Mark', 16, 'adults', 8, 'How does Mark''s Gospel as a whole present Jesus Christ?', 'As the suffering Servant and Son of God — beginning with His divine identity (1:1), demonstrated through authoritative action, and climaxing in His sacrificial death and victorious resurrection', 'Primarily as a moral teacher', 'Only as a political revolutionary', 'Mainly as a miracle worker with no deeper purpose', 'a', 'Mark presents Jesus as the active, authoritative Son of God (1:1) who came to serve and give His life as a ransom for many (10:45), with His identity fully revealed through the cross (15:39).');
